|| (i > 9 && strncasecmp(uri, “gopher://“, 9) == 0)
|| (i > 6 && strncasecmp(uri, “ftp://“,    6) == 0)
|| (i > 5 && strncasecmp(uri, “ldap:”,     5) == 0)
